SELECT material_id, material_name, material_type, unit, unit_price, storage_method, warehouse_code, lot_flag, supply_unit FROM material
material_name LIKE CONCAT('%', #{keyword}, '%')
AND material_type = #{materialType}
AND storage_method = #{storageMethod}
AND lot_flag = #{lotFlag}
ORDER BY ${sortColumn} ${sortOrder}
LIMIT #{perPageNum} OFFSET #{pageStart}

